    if (type === 'success') icon = '✅';
    if (type === 'warning') icon = '⚠️';

    toast.innerHTML = `
        <div class="d-flex align-items-center gap-2">
            <span style="font-size: 1.2em;">${icon}</span>
            <span>${message}</span>
        </div>
