    if (
      (RAW_DATA[cat].foreign && RAW_DATA[cat].foreign.includes(name)) ||
      (RAW_DATA[cat].indian && RAW_DATA[cat].indian.includes(name))
    ) {
      if (cat.toLowerCase().includes("keep")) roleKey = "wk";
