  }

  // Override roleKey from DB if explicit
  if (db.type) roleKey = db.type;

  return {
    name: name,
    price: 10000000, // Dummy price
    roleKey: roleKey,
    playerType: region,
    stats: db,
    cat: roleKey.toUpperCase(),
    set: 1,
  };
}

