// --- DB SANITIZATION HELPERS ---
function deepSanitizePlayers(input) {
  if (!input) return [];
  let data = input;
  // If it's a string, try to parse it
  if (typeof data === "string") {
    try {
      data = JSON.parse(data);
    } catch (e) {
      return [];
    }
  }
  // Now it must be an array
  if (!Array.isArray(data)) return [];

  // Recursively sanitize each element (Mongoose CastError prevention)
  return data
    .map((item) => {
      if (typeof item === "string") {
        try {
          return JSON.parse(item);
        } catch (e) {
          return null;
        }
      }
      return item;
    })
    .filter(Boolean);
}

function deepSanitizeTeams(input) {
  if (!input) return [];
  let data = input;
  if (typeof data === "string") {
    try {
      data = JSON.parse(data);
    } catch (e) {
      return [];
    }
  }
  if (!Array.isArray(data)) return [];

  return data
    .map((team) => {
      let t = team;
      if (typeof t === "string") {
        try {
          t = JSON.parse(t);
        } catch (e) {
          return null;
        }
      }
      if (!t) return null;

      // Sanitize Roster inside team
      if (t.roster) t.roster = deepSanitizePlayers(t.roster);
      return t;
    })
    .filter(Boolean);
}

