          won: team.stats?.w || team.stats?.won || 0,
          lost: team.stats?.l || team.stats?.lost || 0,
          points: team.stats?.pts || team.stats?.points || 0,
          nrr:
            typeof team.stats?.nrr === "number"
              ? team.stats.nrr
