      standings: standings,
      rosters: rosters,

      leagueMatches: (Array.isArray(aiResults.leagueMatches)
        ? aiResults.leagueMatches
        : []
      )
        .map((m) => {
          if (!m || typeof m !== "object") return null;
          return {
            t1: m.t1 || m.team1 || "Unknown",
            t2: m.t2 || m.team2 || "Unknown",
