// Service Worker for IPL Auction PWA
const CACHE_NAME = 'ipl-pro-hub-v3';
const urlsToCache = [
  '/',
  '/ipl.html',
  '/blind-auction.html',
  '/dashboard.html',
  '/profile.html',
  '/style.css',
  '/blind-auction-style.css',
  '/script.js',
