  '/live-stats.js',
  '/chat-enhancements.css',
  '/chat-enhancements.js',
  '/effects.js',
  '/manifest.json'
];

// Install event - cache resources
self.addEventListener('install', event => {
  event.waitUntil(
    caches.open(CACHE_NAME)
      .then(cache => {
        console.log('📦 Caching app shell');
        return cache.addAll(urlsToCache);
      })
      .catch(err => console.log('Cache install error:', err))
  );
  self.skipWaiting();
});

// Activate event - clean up old caches
self.addEventListener('activate', event => {
  event.waitUntil(
    caches.keys().then(cacheNames => {
      return Promise.all(
        cacheNames.map(cacheName => {
          if (cacheName !== CACHE_NAME) {
            console.log('🗑️ Deleting old cache:', cacheName);
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
  self.clients.claim();
});

// Fetch event - Network First, then Cache
self.addEventListener('fetch', event => {
  // Skip non-GET requests
  if (event.request.method !== 'GET') return;
  
  // Skip socket.io and API requests (always network)
  if (event.request.url.includes('socket.io') || 
      event.request.url.includes('/api/')) {
    return;
  }

  event.respondWith(
    fetch(event.request)
      .then(response => {
        // Response valid?
        if (!response || response.status !== 200 || response.type !== 'basic') {
          return response;
        }

        // Update cache with new version
        const responseToCache = response.clone();
        caches.open(CACHE_NAME)
          .then(cache => {
            cache.put(event.request, responseToCache);
          });

        return response;
      })
      .catch(() => {
        // Network failed, try cache
        console.log('Or offline, serving cached version for:', event.request.url);
        return caches.match(event.request)
          .then(response => {
             if (response) return response;
             
             // Fallback for HTML pages
             if (event.request.mode === 'navigate') {
                 return caches.match('/offline.html'); 
             }
             
             // Fallback for images
             if (event.request.destination === 'image') {
                 return new Response('<svg>...</svg>', { headers: { 'Content-Type': 'image/svg+xml' }});
             }

             // LAST RESORT: Return a valid 404/Offline Response instead of undefined
             return new Response('Offline and not cached', { 
                 status: 503, 
                 statusText: 'Service Unavailable',
                 headers: new Headers({ 'Content-Type': 'text/plain' })
             });
          });
      })
  );
